import React, { useState, useMemo } from 'react';
import { useApp } from '../context/AppContext';
import StatusBadge from '../components/workorders/StatusBadge';
import WODetailModal from '../components/workorders/WODetailModal';
import CreateWOModal from '../components/workorders/CreateWOModal';

const FILTERS = [
  { id: 'all',        label: 'All'             },
  { id: 'open',       label: 'Open'            },
  { id: 'assigned',   label: 'Assigned'        },
  { id: 'inprogress', label: 'In Progress'     },
  { id: 'qc',         label: 'Pending QC'      },
  { id: 'pending',    label: 'Pending Approval'},
  { id: 'escalated',  label: 'Escalated'       },
  { id: 'closed',     label: 'Closed'          },
];

// Which WOs each role sees
function filterByRole(workOrders, role) {
  if (role === 'workman')    return workOrders.filter(w => w.workman === 'Suresh P' || w.workman === 'Kiran T');
  if (role === 'supervisor') return workOrders.filter(w => w.supervisor === 'Ramesh K');
  if (role === 'enduser')    return workOrders.filter(w => w.raisedBy.includes('End User'));
  return workOrders;
}

export default function WorkOrders() {
  const { role, workOrders } = useApp();
  const [statusFilter, setStatusFilter] = useState('all');
  const [search, setSearch]             = useState('');
  const [selectedWO, setSelectedWO]     = useState(null);
  const [showCreate, setShowCreate]     = useState(false);

  const canCreate = ['client', 'contractor', 'supervisor'].includes(role);

  const visibleWOs = useMemo(() => {
    let list = filterByRole(workOrders, role);
    if (statusFilter !== 'all') list = list.filter(w => w.status === statusFilter);
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(w =>
        w.id.toLowerCase().includes(q) ||
        w.title.toLowerCase().includes(q) ||
        w.area.toLowerCase().includes(q) ||
        w.contractor.toLowerCase().includes(q)
      );
    }
    return list;
  }, [workOrders, role, statusFilter, search]);

  // Counts per status for filter chips
  const roleWOs = filterByRole(workOrders, role);
  const countByStatus = useMemo(() => {
    const counts = { all: roleWOs.length };
    roleWOs.forEach(w => { counts[w.status] = (counts[w.status] || 0) + 1; });
    return counts;
  }, [roleWOs]);

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">Work Orders</div>
          <div className="page-sub">{roleWOs.length} total in your scope</div>
        </div>
        {canCreate && (
          <button className="btn btn-primary" onClick={() => setShowCreate(true)}>
            + New Work Order
          </button>
        )}
      </div>

      {/* Filter chips */}
      <div className="filter-bar">
        {FILTERS.map(f => (
          <button
            key={f.id}
            className={`filter-chip ${statusFilter === f.id ? 'active' : ''}`}
            onClick={() => setStatusFilter(f.id)}
          >
            {f.label}
            {countByStatus[f.id] > 0 && (
              <span style={{ marginLeft:4, opacity:0.65 }}>({countByStatus[f.id] || 0})</span>
            )}
          </button>
        ))}
        <input
          className="search-input"
          placeholder="Search by title, area, contractor..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
      </div>

      {/* Table */}
      <div className="card">
        {visibleWOs.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">🔧</div>
            <div className="empty-title">No work orders found</div>
            <div className="empty-sub">Try adjusting the filters or search term</div>
          </div>
        ) : (
          <table className="data-table">
            <thead>
              <tr>
                <th style={{ width: 240 }}>Work Order</th>
                <th>Area</th>
                <th>Contractor</th>
                <th>Priority</th>
                <th>Status</th>
                <th>SLA</th>
                <th>Due</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {visibleWOs.map(wo => {
                const slaPct = Math.min(Math.round((wo.elapsedHours / wo.slaHours) * 100), 100);
                const slaColor = slaPct >= 100 ? 'var(--danger)' : slaPct >= 80 ? 'var(--warning)' : 'var(--success)';
                return (
                  <tr key={wo.id} onClick={() => setSelectedWO(wo)}>
                    <td>
                      <span style={{ fontSize:11, color:'var(--text-3)', display:'block' }}>{wo.id}</span>
                      <span style={{ fontWeight:500 }}>{wo.title}</span>
                    </td>
                    <td style={{ color:'var(--text-2)', fontSize:12 }}>{wo.area}</td>
                    <td>{wo.contractor}</td>
                    <td className={`priority-${wo.priority.toLowerCase()}`}>{wo.priority}</td>
                    <td><StatusBadge status={wo.status} /></td>
                    <td>
                      <div style={{ display:'flex', alignItems:'center', gap:6 }}>
                        <div className="sla-bar-wrap" style={{ width:60 }}>
                          <div className="sla-bar" style={{ width:`${slaPct}%`, background:slaColor }} />
                        </div>
                        <span style={{ fontSize:11, color:slaColor, fontWeight:600 }}>{slaPct}%</span>
                      </div>
                    </td>
                    <td style={{
                      color: wo.status === 'escalated' ? 'var(--danger)' : wo.due === '27 Apr' ? 'var(--warning)' : 'var(--text-2)',
                      fontWeight: (wo.status === 'escalated' || wo.due === '27 Apr') ? 600 : 400,
                    }}>
                      {wo.due === '27 Apr' ? 'Today' : wo.due}
                    </td>
                    <td onClick={e => e.stopPropagation()}>
                      <button className="btn btn-sm" onClick={() => setSelectedWO(wo)}>View</button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>

      {/* Modals */}
      {selectedWO && (
        <WODetailModal
          wo={workOrders.find(w => w.id === selectedWO.id)}
          onClose={() => setSelectedWO(null)}
        />
      )}
      {showCreate && <CreateWOModal onClose={() => setShowCreate(false)} />}
    </div>
  );
}
